package main

import (
	"log"
	"os"

	"github.com/gin-gonic/gin"

	"auth-user-management-service/config"
)

func main() {
	// Nạp cấu hình từ .env
	config.LoadEnv()

	// Kết nối và Auto Migrate Databa
	config.ConnectDB()

	// Khởi tạo Gin App (tương tự SpringApplication.run)
	r := gin.Default()

	// API Health check
	r.GET("/health", func(c *gin.Context) {
		c.JSON(200, gin.H{
			"status":  "UP",
			"service": "auth-user-management-service",
		})
	})

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	log.Printf("Server is starting on port http://localhost:%s\n", port)

	// Khởi chạy server
	if err := r.Run(":" + port); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

package main

import (
	"log"
	"os"

	"github.com/gin-gonic/gin"

	"auth-user-management-service/config"
	"auth-user-management-service/internal/handler"
	"auth-user-management-service/internal/repository"
	"auth-user-management-service/internal/usecase"
)

func main() {
	// Load configuration from .env
	config.LoadEnv()

	// Connect and Auto Migrate Database
	config.ConnectDB()

	// -----------------------------
	// Dependency Injection (Manual)
	// -----------------------------
	// 1. Initialize Repository layer
	userRepo := repository.NewUserRepository(config.DB)

	// 2. Initialize Usecase layer
	authUsecase := usecase.NewAuthUsecase(userRepo)

	// 3. Initialize Handler layer
	authHandler := handler.NewAuthHandler(authUsecase)

	// Initialize Gin App (similar to SpringApplication.run)
	r := gin.Default()

	// Health check API
	r.GET("/health", func(c *gin.Context) {
		c.JSON(200, gin.H{
			"status":  "UP",
			"service": "auth-user-management-service",
		})
	})

	// -----------------------------
	// API Routes Grouping
	// -----------------------------
	api := r.Group("/api/v1")
	{
		auth := api.Group("/auth")
		{
			// POST /api/v1/auth/register
			auth.POST("/register", authHandler.Register)
		}
	}

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	log.Printf("Server is starting on port http://localhost:%s\n", port)

	// Start the server
	if err := r.Run(":" + port); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

package config

import (
	"fmt"
	"log"
	"os"

	"auth-user-management-service/internal/domain"

	"github.com/joho/godotenv"
	"gorm.io/driver/postgres"
	"gorm.io/gorm"
)

var DB *gorm.DB

func LoadEnv() {
	err := godotenv.Load()
	if err != nil {
		log.Println("No .env file found, using system environment variables")
	}
}

func ConnectDB() {
	host := os.Getenv("DB_HOST")
	port := os.Getenv("DB_PORT")
	user := os.Getenv("DB_USER")
	password := os.Getenv("DB_PASSWORD")
	dbname := os.Getenv("DB_NAME")

	dsn := fmt.Sprintf("host=%s user=%s password=%s dbname=%s port=%s sslmode=disable TimeZone=Asia/Ho_Chi_Minh",
		host, user, password, dbname, port)

	db, err := gorm.Open(postgres.Open(dsn), &gorm.Config{})
	if err != nil {
		log.Fatalf("Failed to connect to database: %v", err)
	}

	fmt.Println("Connected to PostgreSQL successfully!")
	DB = db

	// Auto Migration: GORM sẽ tự động tạo bảng nếu chưa có (Giống chế độ update của Hibernate)
	err = db.AutoMigrate(&domain.User{})
	if err != nil {
		log.Fatalf("Failed to auto migrate: %v", err)
	}
	fmt.Println("Auto migration completed!")
}

