package domain

import (
	"time"

	"gorm.io/gorm"
)

// User đại diện cho bản ghi user trong DB (Entity/Model)
type User struct {
	ID        uint           `gorm:"primaryKey;autoIncrement" json:"userId"`
	Username  string         `gorm:"type:varchar(100);not null" json:"username"`
	Email     string         `gorm:"type:varchar(100);uniqueIndex;not null" json:"email"`
	Password  string         `gorm:"type:varchar(255);not null" json:"-"` // Giấu password khi parse/marshal JSON
	Role      string         `gorm:"type:varchar(50);not null;default:'member'" json:"role"` // manager hoặc member
	CreatedAt time.Time      `json:"createdAt"`
	UpdatedAt time.Time      `json:"updatedAt"`
	DeletedAt gorm.DeletedAt `gorm:"index" json:"-"`
}

package domain

import (
	"time"

	"gorm.io/gorm"
)

// User represents the user record in the database (Entity/Model)
type User struct {
	ID        uint           `gorm:"primaryKey;autoIncrement" json:"userId"`
	Username  string         `gorm:"type:varchar(100);not null" json:"username"`
	Email     string         `gorm:"type:varchar(100);uniqueIndex;not null" json:"email"`
	Password  string         `gorm:"type:varchar(255);not null" json:"-"` // Hide password when parse/marshal JSON
	Role      string         `gorm:"type:varchar(50);not null;default:'member'" json:"role"` // manager or member
	CreatedAt time.Time      `json:"createdAt"`
	UpdatedAt time.Time      `json:"updatedAt"`
	DeletedAt gorm.DeletedAt `gorm:"index" json:"-"`
}

package repository

import (
	"auth-user-management-service/internal/domain"
	"gorm.io/gorm"
)

// UserRepository defines the database operations for User
type UserRepository interface {
	CreateUser(user *domain.User) error
	FindByEmail(email string) (*domain.User, error)
}

type userRepositoryImpl struct {
	db *gorm.DB
}

// NewUserRepository creates a new user repository instance
func NewUserRepository(db *gorm.DB) UserRepository {
	return &userRepositoryImpl{db: db}
}

func (r *userRepositoryImpl) CreateUser(user *domain.User) error {
	return r.db.Create(user).Error
}

func (r *userRepositoryImpl) FindByEmail(email string) (*domain.User, error) {
	var user domain.User
	// Find the first record matching the email. Returns gorm.ErrRecordNotFound if none found.
	err := r.db.Where("email = ?", email).First(&user).Error
	if err != nil {
		return nil, err
	}
	return &user, nil
}

package usecase

import (
	"errors"

	"auth-user-management-service/internal/domain"
	"auth-user-management-service/internal/repository"
	"auth-user-management-service/pkg/utils"
)

// RegisterRequest defines the input payload for user registration
type RegisterRequest struct {
	Username string `json:"username" binding:"required"`
	Email    string `json:"email" binding:"required,email"`
	Password string `json:"password" binding:"required,min=6"`
	Role     string `json:"role"` // Optional: manager or member
}

// AuthUsecase defines the business logic interface
type AuthUsecase interface {
	Register(req *RegisterRequest) (*domain.User, error)
}

type authUsecaseImpl struct {
	userRepo repository.UserRepository
}

// NewAuthUsecase creates a new usecase instance (Dependency Injection)
func NewAuthUsecase(userRepo repository.UserRepository) AuthUsecase {
	return &authUsecaseImpl{
		userRepo: userRepo,
	}
}

// Register processes the user registration logic
func (u *authUsecaseImpl) Register(req *RegisterRequest) (*domain.User, error) {
	// 1. Check if email already exists
	existingUser, _ := u.userRepo.FindByEmail(req.Email)
	if existingUser != nil {
		return nil, errors.New("email already in use")
	}

	// 2. Hash the password
	hashedPassword, err := utils.HashPassword(req.Password)
	if err != nil {
		return nil, errors.New("failed to hash password")
	}

	// 3. Assign role (default is member, strict definition)
	role := "member"
	if req.Role == "manager" {
		role = "manager"
	}

	// 4. Create the domain.User entity
	newUser := &domain.User{
		Username: req.Username,
		Email:    req.Email,
		Password: hashedPassword,
		Role:     role,
	}

	// 5. Save using repository
	if err := u.userRepo.CreateUser(newUser); err != nil {
		return nil, errors.New("failed to create user")
	}

	return newUser, nil
}

package utils

import "golang.org/x/crypto/bcrypt"

// HashPassword thay chức năng của BCryptPasswordEncoder trong Java
func HashPassword(password string) (string, error) {
	// Cost = 14 là độ phức tạp của thuật toán mã hóa (an toàn)
	bytes, err := bcrypt.GenerateFromPassword([]byte(password), 14)
	return string(bytes), err
}

// CheckPasswordHash dùng để so sánh pass lúc Login sau này
func CheckPasswordHash(password, hash string) bool {
	err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(password))
	return err == nil
}

package utils

import "golang.org/x/crypto/bcrypt"

// HashPassword encrypts password using bcrypt
func HashPassword(password string) (string, error) {
	// Cost = 14 is the complexity of the encryption algorithm
	bytes, err := bcrypt.GenerateFromPassword([]byte(password), 14)
	return string(bytes), err
}

// CheckPasswordHash compares a hashed password with a plaintext one
func CheckPasswordHash(password, hash string) bool {
	err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(password))
	return err == nil
}
